class RangeModule:

    def __init__(self):
        self.intervals = []

    def addRange(self, left: int, right: int) -> None:
        self.removeRange(left, left)
        self.removeRange(right - 1, right)
        self.intervals.append((left, right))

        i = 0
        while i < len(self.intervals) - 1:
            if self.intervals[i][1] >= self.intervals[i + 1][0]:
                self.intervals[i] = (self.intervals[i][0], max(self.intervals[i][1], self.intervals[i + 1][1]))
                del self.intervals[i + 1]
            else:
                i += 1

    def queryRange(self, left: int, right: int) -> bool:
        for start, end in self.intervals:
            if start <= left and right <= end:
                return True
            elif left < start and end < right:
                return False
        return False

    def removeRange(self, left: int, right: int) -> None:
        self.removeRangeHelper(left, right, 0)
        self.intervals = [(start, end) for start, end in self.intervals if start < end]

    def removeRangeHelper(self, left: int, right: int, index: int) -> None:
        if index >= len(self.intervals):
            return
        if left <= self.intervals[index][0] and self.intervals[index][1] <= right:
            del self.intervals[index]
            self.removeRangeHelper(left, right, index - 1)
            self.removeRangeHelper(left, right, index)
        elif left < self.intervals[index][0] and self.intervals[index][1] < right:
            self.intervals[index] = (self.intervals[index][0], left)
            self.removeRangeHelper(left, right, index + 1)
        elif left > self.intervals[index][0] and self.intervals[index][1] > right:
            self.intervals[index] = (right, self.intervals[index][1])
            self.removeRangeHelper(left, right, index + 1)
        else:
            self.removeRangeHelper(left, right, index + 1)
